 1	import { Flex, FlexItem, Menu, MenuContent, MenuItem, MenuList } from '@patternfly/react-core';
 2	import React from 'react';
 3	import { FilterCompare } from '../../../model/filters';
 4	import { FormUpdateResult, Suggestion } from './filter-search-input';
 5	
 6	export interface FilterSearchSuggestionsProps {
 7	  suggestions: Suggestion[];
 8	  setSuggestions: (suggestions: Suggestion[]) => void;
 9	  searchInput: HTMLInputElement | null;
10	  searchInputValue: string;
11	  updateForm: (value: string, validate?: boolean) => FormUpdateResult;
12	  onSearchChange: (value: string) => void;
13	}
14	
15	export const FilterSearchSuggestions: React.FC<FilterSearchSuggestionsProps> = ({
16	  suggestions,
17	  setSuggestions,
18	  searchInput,
19	  searchInputValue,
20	  updateForm,
21	  onSearchChange
22	}) => {
23	  return (
24	    <Menu
25	      onKeyDown={e => {
26	        if (e.key === 'Escape') {
27	          e.preventDefault();
28	          // clear suggestions on esc key
29	          setSuggestions([]);
30	          searchInput?.focus();
31	        }
32	      }}
33	    >
34	      <MenuContent>
35	        <MenuList>
36	          {suggestions.map((suggestion, index) => (
37	            <MenuItem
38	              id={`suggestion-${index}`}
39	              itemId={suggestion}
40	              key={`suggestion-${index}`}
41	              onKeyDown={e => {
42	                if (index === 0 && e.key === 'ArrowUp') {
43	                  e.preventDefault();
44	                  searchInput?.focus();
45	                }
46	              }}
47	              onClick={() => {
48	                const updated = updateForm(searchInputValue);
49	                if (!updated.def) {
50	                  if (!suggestion.validate) {
51	                    onSearchChange(suggestion.value);
52	                  } else {
53	                    updateForm(suggestion.value, true);
54	                  }
55	                } else if (!updated.comparator) {
56	                  // check if it's a valid comparator
57	                  if ((Object.values(FilterCompare) as string[]).includes(suggestion.value)) {
58	                    onSearchChange(`${updated.def.id}${suggestion.value}`);
59	                  } else {
60	                    // else consider this as a field since ids can overlap (name / namespace)
61	                    onSearchChange(suggestion.value);
62	                  }
63	                } else {
64	                  updateForm(`${updated.def.id}${updated.comparator}${suggestion.value}`, true);
65	                }
66	              }}
67	            >
68	              <Flex direction={{ default: 'row' }}>
69	                <FlexItem className="filter-text-ellipsis" flex={{ default: 'flex_1' }}>
70	                  {suggestion.value}
71	                </FlexItem>
72	                <FlexItem className="filter-text-ellipsis" flex={{ default: 'flex_1' }}>
73	                  {suggestion.display}
74	                </FlexItem>
75	              </Flex>
76	            </MenuItem>
77	          ))}
78	        </MenuList>
79	      </MenuContent>
80	    </Menu>
81	  );
82	};

